const fs = require('fs');
const http = require('http');
const https = require('https');
let ctx = {};
try { ctx = JSON.parse(fs.readFileSync('/data/KAI_Context.json', 'utf8').replace(/^\uFEFF/, '')); } catch(e) { ctx = {}; }
const entities = ctx.entities || {};
const founder = ctx.founder || {};
const revenue = ctx.revenue_targets || {};
const activeDeadlines = (ctx.deadlines || []).filter(function(d) {
  const st = (d.status || '').toUpperCase();
  return st !== 'FILED' && st !== 'COMPLETE' && st !== 'EXEMPT';
});
const eafProfile = 'ORGANIZATION: ' + (entities.EAF && entities.EAF.name ? entities.EAF.name : 'KAI-Netics Equity & Autonomy Foundry') +
  '\nEIN: ' + (entities.EAF && entities.EAF.ein ? entities.EAF.ein : '41-4820296') +
  '\nTYPE: ' + (entities.EAF && entities.EAF.type ? entities.EAF.type : 'Maryland Nonstock Corp 501c3 pending') +
  '\nFOUNDER: ' + (founder.name || '') + ' -- ' + (founder.credentials || []).join(', ') +
  '\nPROGRAMS: CAKO | MONK | Talent Pipeline Agreement' +
  '\nSERVICE AREA: Maryland, DC Metro, Northern Virginia' +
  '\nREVENUE: Y1 ' + (revenue.year1_total || '') + ' Y2 ' + (revenue.year2_total || '') +
  '\nACTIVE DEADLINES: ' + activeDeadlines.map(function(d) { return d.item + ' | ' + d.date; }).join(' | ') +
  '\nCOMPLIANCE: NO funds flow FP to EAF. Talent Pipeline Agreement is only structural link.';

const sendWhatsApp = async function(text) {
  const mb = JSON.stringify({ number: '14432576836@s.whatsapp.net', textMessage: { text: text } });
  const wo = { hostname: 'host.docker.internal', port: 8081, path: '/message/sendText/Aidan', method: 'POST', headers: { 'Content-Type': 'application/json', 'apikey': 'Kevin2026', 'Content-Length': Buffer.byteLength(mb) } };
  await new Promise(function(r) { const req = http.request(wo, function(res) { res.on('data',function(){}); res.on('end',r); }); req.on('error',r); req.write(mb); req.end(); });
};

const sendCallback = async function(summary, sessionId) {
  const cbBody = JSON.stringify({ agent: 'Jordan', summary: summary, fitScore: 'N/A', fileName: 'skipped', supabaseLogged: false, sessionId: sessionId || null, timestamp: new Date().toISOString() });
  const cbOpts = { hostname: 'host.docker.internal', port: 5678, path: '/webhook/aidan-callback', method: 'POST', headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(cbBody) } };
  const cbReq = http.request(cbOpts, function(res) { res.on('data',function(){}); res.on('end',function(){}); });
  cbReq.on('error',function(){});
  cbReq.write(cbBody);
  cbReq.end();
};

const sessionId = $input.first().json.sessionId || null;
const isScheduled = !$input.first().json.command;

const supabaseUrl = $env.SUPABASE_URL || '';
const supabaseKey = $env.SUPABASE_SERVICE_KEY || '';
const supabaseHost = supabaseUrl.replace('https://', '').replace('http://', '');
let executionId = null;
try {
  const execRecord = JSON.stringify({
    agent: 'Jordan',
    trigger_type: isScheduled ? 'cron' : 'orchestra',
    status: 'success',
    workflow_version: 'v3',
    notes: 'grant_writer'
  });
  const execResult = await new Promise(function(resolve, reject) {
    const req = https.request({
      hostname: supabaseHost, port: 443,
      path: '/rest/v1/agent_executions',
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'apikey': supabaseKey,
        'Authorization': 'Bearer ' + supabaseKey,
        'Prefer': 'return=representation',
        'Content-Length': Buffer.byteLength(execRecord)
      }
    }, function(res) {
      let d = '';
      res.on('data', function(c) { d += c; });
      res.on('end', function() { resolve({ status: res.statusCode, body: d }); });
    });
    req.on('error', reject);
    req.write(execRecord);
    req.end();
  });
  if (execResult.status === 201) {
    const rows = JSON.parse(execResult.body);
    executionId = rows && rows[0] ? rows[0].id : null;
  }
} catch(e) {}

const dirPath = '/data/Maryland_Grants/';
let grantFiles = [];
try { grantFiles = fs.readdirSync(dirPath).filter(function(f) { return f.endsWith('.txt') || f.endsWith('.md'); }); } catch(e) { grantFiles = []; }

if (grantFiles.length === 0) {
  const summary = 'JORDAN: No grant files found in /data/Maryland_Grants/. Add grant files to analyze.';
  await sendWhatsApp(summary);
  await sendCallback(summary, sessionId);
  return [{ json: { fileName: 'none', content: '', eafProfile: eafProfile, noFiles: true, sessionId: sessionId, executionId: executionId } }];
}

const today = new Date().toISOString().slice(0, 10);
const reportDir = '/data/Aidan_Outputs/Jordan/';
let analyzedToday = [];
try {
  analyzedToday = fs.readdirSync(reportDir)
    .filter(function(f) { return f.startsWith('Grant_Report_' + today); })
    .map(function(f) {
      return f.replace('Grant_Report_' + today, '').replace(/^T[\d\-]+_/, '').replace(/_/g,' ').replace('.txt','').toLowerCase();
    });
} catch(e) { analyzedToday = []; }

const filesToProcess = grantFiles.filter(function(file) {
  const normalizedFile = file.replace(/_/g,' ').replace('.txt','').replace('.md','').toLowerCase();
  return !analyzedToday.some(function(done) {
    return done.indexOf(normalizedFile.substring(0,20)) !== -1;
  });
});

if (filesToProcess.length === 0) {
  const summary = 'JORDAN: All ' + grantFiles.length + ' grant files already analyzed today (' + today + ').\nFiles: ' + grantFiles.join(', ') + '\nSay Jordan grant tomorrow for fresh analysis.';
  await sendWhatsApp(summary);
  await sendCallback(summary, sessionId);
  return [{ json: { fileName: 'skipped', content: '', eafProfile: eafProfile, noFiles: true, sessionId: sessionId, executionId: executionId } }];
}

return filesToProcess.map(function(file) {
  let content = '';
  try { content = fs.readFileSync(dirPath + file, 'utf8'); } catch(e) { content = 'Could not read: ' + e.message; }
  return { json: { fileName: file, content: content, eafProfile: eafProfile, noFiles: false, sessionId: sessionId, executionId: executionId } };
});

